TUSDATA.infra=[
{id:"portny",name:"Port of New York",lon:-74.05,lat:40.67,from:1750,kind:"port",tier:1,
 facts:[["Erie Canal","After 1825 the canal made New York the nation's dominant port"],["Container age","The first container ship, Ideal X, sailed from Port Newark in 1956"]],
 eras:[
  {from:1750,to:1825,text:"New York's deep, ice-free harbor at the Hudson's mouth made it a leading colonial port for flour, furs, and British manufactures. Merchants, artisans, and enslaved dockworkers — colonial New York held more enslaved people than any other northern city — moved cargo across East River wharves serving packet ships to London and the West Indies."},
  {from:1825,to:1956,text:"The Erie Canal (1825) funneled the Midwest's grain through Manhattan, making New York the nation's dominant port, handling well over half of U.S. imports by mid-century. Irish and later Italian longshoremen worked the piers, while Castle Garden and Ellis Island landed millions of immigrants a few hundred yards from the docks."},
  {from:1956,to:2026,text:"In 1956 Malcom McLean's Ideal X sailed from Port Newark carrying the first shipping containers. Container cranes moved the cargo trade to New Jersey's rail-served flatlands, emptying Manhattan's finger piers. The Port Authority's Newark-Elizabeth complex remains the East Coast's busiest container gateway, its channels deepened and the Bayonne Bridge raised for post-Panamax ships."}
 ],
 sources:["Port Authority of New York and New Jersey","National Park Service","Library of Congress"]},
{id:"portcharleston",name:"Port of Charleston",lon:-79.92,lat:32.78,from:1750,kind:"port",tier:3,
 facts:[["Slave trade","An estimated 40 percent of enslaved Africans brought to North America landed at Charleston"],["Today","A 52-foot channel, completed 2022, is the deepest on the East Coast"]],
 eras:[
  {from:1750,to:1808,text:"Charleston grew rich shipping rice and indigo grown by enslaved Africans, whose knowledge of rice culture underpinned the Lowcountry economy. It became British North America's wealthiest city and its largest slave port — roughly 40 percent of enslaved Africans brought to the mainland landed here, many at Gadsden's Wharf after quarantine on Sullivan's Island."},
  {from:1808,to:1865,text:"After Congress banned the Atlantic slave trade in 1808, cotton dominated the wharves and the domestic trade in enslaved people continued. Secession began here: the April 1861 bombardment of Fort Sumter in the harbor opened the Civil War, and Union blockade and siege left the port in ruins by 1865."},
  {from:1865,to:2026,text:"Phosphate fertilizer and naval spending revived the harbor, and the Navy yard anchored the economy until its 1996 closure. The State Ports Authority, created in 1942, built major container terminals; a 52-foot harbor deepening finished in 2022 made Charleston the East Coast's deepest port. The International African American Museum opened at Gadsden's Wharf in 2023."}
 ],
 sources:["South Carolina Ports Authority","National Park Service","International African American Museum"]},
{id:"portno",name:"Port of New Orleans",lon:-90.06,lat:29.94,from:1750,kind:"port",tier:2,
 facts:[["Cotton era","By the 1840s New Orleans shipped roughly half of U.S. cotton exports"],["Slave market","The city held the nation's largest slave market before the Civil War"]],
 eras:[
  {from:1750,to:1815,text:"Founded by the French in 1718 where the Mississippi nears Lake Pontchartrain, New Orleans controlled the continent's greatest river outlet. Furs, tobacco, and sugar moved through under French and Spanish rule; the 1803 Louisiana Purchase secured the port for western farmers, and Jackson's 1815 victory at Chalmette confirmed American control."},
  {from:1815,to:1865,text:"Steamboats made New Orleans the South's great entrepot — among the world's busiest ports by the 1840s, shipping roughly half the nation's cotton exports. It was also the largest slave market in the United States: tens of thousands of enslaved people were sold through its auction houses and pens to the cotton and sugar frontiers."},
  {from:1865,to:2026,text:"Grain elevators, banana imports, and barge traffic sustained the port; the Industrial Canal (1923) and container terminals modernized it, and the lower Mississippi complex remains America's largest grain export gateway. Hurricane Katrina's 2005 levee failures flooded the city, though the port reopened within weeks. Petrochemical plants now line the river upstream."}
 ],
 sources:["Port of New Orleans","Library of Congress","The Historic New Orleans Collection"]},
{id:"springfield",name:"Springfield Armory",lon:-72.59,lat:42.11,from:1794,to:1968,kind:"factory",tier:2,
 facts:[["Innovation","Blanchard's pattern-tracing lathe (1819) advanced interchangeable manufacture"],["Icon","John Garand developed the M1 rifle here; adopted 1936"]],
 eras:[
  {from:1794,to:1865,text:"George Washington sited the federal armory on a hill above the Connecticut River in 1794, on grounds that had stored Revolutionary arms since 1777. Here armory practice — gauges, division of labor, and Thomas Blanchard's pattern-tracing lathe of 1819 — helped create the American system of interchangeable manufacture. Civil War production reached roughly 1,000 rifle-muskets a day."},
  {from:1865,to:1968,text:"The armory produced the trapdoor Springfields, the M1903 rifle, and John Garand's M1, the semi-automatic rifle of WWII, developed on site over fifteen years. Skilled machinists — joined by thousands of women workers during both world wars — pushed employment above 13,000 at the WWII peak. The Pentagon ordered closure in 1964 over fierce local protest."},
  {from:1968,to:2026,text:"Federal arms-making ended in 1968 after 174 years. Springfield Technical Community College took over much of the campus, and the National Park Service preserves the historic core as Springfield Armory National Historic Site, home to one of the world's largest collections of historic American military firearms."}
 ],
 sources:["National Park Service (Springfield Armory NHS)","Smithsonian Institution"]},
{id:"anthracite",name:"Anthracite coal country",lon:-75.66,lat:41.41,from:1820,to:1960,kind:"coalfield",tier:2,
 facts:[["Peak","About 100 million tons mined and roughly 180,000 workers around 1917"],["1902","The Great Anthracite Strike brought the first federal arbitration of a labor dispute"]],
 eras:[
  {from:1820,to:1875,text:"Nearly all U.S. anthracite — hard, clean-burning coal — lay under five counties of northeastern Pennsylvania. Canals and gravity railroads carried it to Philadelphia and New York, where it heated homes and fired early iron furnaces. Welsh, Irish, and German miners worked company patch towns; the 1869 Avondale fire killed 110 men and boys and spurred the first state mine-safety laws."},
  {from:1875,to:1930,text:"Railroad cartels controlled the fields; the Molly Maguire trials sent twenty Irish miners to the gallows on private-detective evidence. Breaker boys picked slate beside immigrant fathers. At the 1917 peak, about 180,000 workers mined nearly 100 million tons a year. The 1902 strike of some 147,000 miners ended in Theodore Roosevelt's arbitration — a first for federal labor relations."},
  {from:1930,to:2026,text:"Oil and gas heating destroyed the market after WWII. The 1959 Knox Mine disaster, when the Susquehanna River broke into workings tunneled beneath it, effectively ended deep mining. Culm banks, subsidence, and acid drainage scar the region; the Centralia mine fire, burning since 1962, emptied an entire town. Small surface operations and heritage museums remain."}
 ],
 sources:["Pennsylvania Historical and Museum Commission","Anthracite Heritage Museum","Library of Congress"]},
{id:"baldwin",name:"Baldwin Locomotive Works",lon:-75.16,lat:39.96,from:1832,to:1956,kind:"factory",tier:3,
 facts:[["Scale","More than 70,000 locomotives built over 124 years"],["Miss","Stayed with steam too long; diesel rivals took the market by the 1950s"]],
 eras:[
  {from:1832,to:1901,text:"Jeweler-machinist Matthias Baldwin built Old Ironsides, his first locomotive, in Philadelphia in 1832. Surrounded by the Pennsylvania Railroad's network and the city's machine-shop trades, Baldwin Locomotive Works grew into the world's largest locomotive builder, exporting engines to every continent. Baldwin himself, an abolitionist who funded a school for Black children, faced Southern boycotts."},
  {from:1901,to:1928,text:"At its peak Baldwin employed close to 20,000 at Broad Street and its vast new Eddystone plant, delivering more than 2,500 locomotives a year. Management fiercely resisted unions. WWI brought rifle and artillery work; in 1917 an ammunition plant on the Eddystone property exploded, killing about 140 workers, most of them women and girls."},
  {from:1928,to:2026,text:"Baldwin consolidated at Eddystone in 1928, then bet on steam and lost: General Motors diesels took the postwar market, and the last Baldwin locomotives were delivered in 1956. The Philadelphia works were demolished; Matthias Baldwin's name survives on a downtown park, and Baldwin engines still steam on heritage railroads worldwide."}
 ],
 sources:["Railroad Museum of Pennsylvania","Smithsonian Institution"]},
{id:"calgold",name:"Mother Lode goldfields",lon:-121.06,lat:38.80,from:1848,to:1884,kind:"mine",tier:1,
 facts:[["Migration","Roughly 300,000 people reached California during the rush"],["Law","The 1884 Sawyer decision against hydraulic mining debris was the first major U.S. environmental ruling"]],
 eras:[
  {from:1848,to:1852,text:"James Marshall's find at Sutter's Mill in January 1848 triggered history's greatest gold rush: some 300,000 people came by sea and overland trail. Forty-niners panned placer gravels along the Mother Lode; San Francisco exploded from village to metropolis, and California vaulted to statehood in 1850 on gold's momentum."},
  {from:1852,to:1884,text:"As surface gold thinned, capital took over: river-damming companies, deep quartz mines, and hydraulic monitors that blasted whole hillsides into sluices. Mining debris buried Central Valley farms and choked rivers until the 1884 Sawyer decision halted hydraulic mining — the first major U.S. environmental ruling. Chinese miners, taxed and mobbed, reworked claims others abandoned."},
  {from:1884,to:2026,text:"For Native Californians the rush was catastrophic: disease, dispossession, and state-funded militia campaigns cut the Indigenous population from perhaps 150,000 to about 30,000 by 1870. Hardrock mining lingered — Empire Mine ran until 1956 — and today state parks preserve Coloma and Malakoff Diggins, where the hydraulic scars are still bare a century on."}
 ],
 sources:["California State Parks","California State Library","Library of Congress"]},
{id:"comstock",name:"Comstock Lode",lon:-119.65,lat:39.31,from:1859,to:1898,kind:"mine",tier:2,
 facts:[["Yield","About $300 million in silver and gold by the 1880s"],["Deep mining","Square-set timbering and the Sutro Tunnel pioneered deep, hot-rock mining"]],
 eras:[
  {from:1859,to:1877,text:"The first great American silver strike, found in 1859 under Mount Davidson, built Virginia City almost overnight. Philipp Deidesheimer's square-set timbering let miners work huge, scalding-hot ore bodies far underground; Cornish and Irish miners earned a then-remarkable four dollars a day. The 1873 Big Bonanza made the Silver Kings and helped finance San Francisco's rise."},
  {from:1877,to:1898,text:"Adolph Sutro's four-mile drainage tunnel reached the lode in 1878, just as the bonanzas gave out. Output collapsed in the 1880s, and by 1898 major mining had ended after some $300 million in silver and gold. Whole Sierra forests had gone underground as square-set timber or up in smoke as cordwood and charcoal."},
  {from:1898,to:2026,text:"Virginia City shrank from over 20,000 people to a few hundred, then found an afterlife as a National Historic Landmark district — Mark Twain, who took his pen name reporting for the Territorial Enterprise, is its favorite ghost. Mercury used in silver milling still contaminates the Carson River watershed downstream, now a federal Superfund concern."}
 ],
 sources:["Nevada Historical Society","National Park Service","U.S. Environmental Protection Agency"]},
{id:"titusville",name:"Drake Well — Oil Creek",lon:-79.67,lat:41.63,from:1859,kind:"oilfield",tier:1,
 facts:[["First","August 27, 1859 — first purpose-drilled U.S. oil well"],["Effect","Kerosene replaced whale oil within a decade"]],
 eras:[
  {from:1859,to:1901,text:"Edwin Drake, drilling for the Seneca Oil Company beside Oil Creek where petroleum seeped naturally, struck oil at 69.5 feet on August 27, 1859. Boomtowns like Pithole rose and vanished within months; teamsters, coopers, and drillers swarmed the narrow valley. Kerosene from Pennsylvania crude lit the world's lamps, and Rockefeller's Standard Oil grew rich refining it."},
  {from:1901,to:2026,text:"Spindletop and the mid-continent fields dwarfed the region after 1901, though Pennsylvania-grade crude stayed prized for lubricants. Titusville settled into small-scale production and memory: the Drake Well Museum's reconstructed engine house marks the industry's birthplace, and stripper wells still nod along Oil Creek in a state park built on the old boom grounds."}
 ],
 sources:["Drake Well Museum (Pennsylvania Historical and Museum Commission)","American Petroleum Institute"]},
{id:"stockyards",name:"Union Stock Yards",lon:-87.66,lat:41.82,from:1865,to:1971,kind:"factory",tier:2,
 facts:[["Peak","More than 18 million head of livestock received in 1924"],["Reform","The Jungle (1906) spurred federal meat inspection within months"]],
 eras:[
  {from:1865,to:1906,text:"Nine railroads opened the consolidated yards on Christmas Day 1865 on marshy prairie southwest of Chicago. Gustavus Swift's refrigerated railcars in the late 1870s let dressed beef undersell local butchers nationwide, and Armour, Swift, and Morris built an industrial slaughter empire on the square mile of pens that made Chicago hog butcher for the world."},
  {from:1906,to:1945,text:"Upton Sinclair's The Jungle (1906) exposed packinghouse conditions and helped pass the Meat Inspection and Pure Food and Drug Acts within months. Irish, Polish, and Lithuanian workers of Back of the Yards were joined by Black Southern migrants; strikebreaking and the 1919 race riot divided them until the CIO packinghouse union won interracial contracts in the 1930s and 1940s. Receipts peaked above 18 million animals in 1924."},
  {from:1945,to:2026,text:"Trucking, interstate highways, and slaughter near the feedlots made central yards obsolete; the big packers left in the 1950s and the yards closed on July 30, 1971. The limestone gate still stands beside an industrial park, and Bubbly Creek — the river arm once choked with packinghouse waste — remains Chicago's most stubborn environmental relic."}
 ],
 sources:["Chicago History Museum","Encyclopedia of Chicago (Newberry Library)","Library of Congress"]},
{id:"applachcoal",name:"Appalachian coalfields",lon:-81.60,lat:37.80,from:1870,kind:"coalfield",tier:1,
 facts:[["Blair Mountain","1921 — about 10,000 miners fought in the largest U.S. armed labor uprising since the Civil War"],["Company towns","Miners were often paid in scrip good only at company stores"]],
 eras:[
  {from:1870,to:1902,text:"Railroads pushing into the mountains after the Civil War opened thick bituminous seams across West Virginia, eastern Kentucky, Virginia, and Tennessee. Smokeless Pocahontas and New River coal fired Navy ships and Pittsburgh steel. Operators recruited a deliberate mix of white Appalachians, Black Southern migrants, and Italian and Hungarian immigrants into isolated company towns paid in scrip."},
  {from:1902,to:1950,text:"The mine wars made the coalfields a battleground: Paint Creek-Cabin Creek (1912-13), the Matewan shootout (1920), and the Battle of Blair Mountain (1921), where perhaps 10,000 armed miners marched for the union until the Army arrived — the largest armed uprising in America since the Civil War. The UMWA finally organized the fields under the New Deal."},
  {from:1950,to:2026,text:"Mechanization gutted employment — U.S. coal jobs fell from over 700,000 in the 1920s to a small fraction — and Appalachia bled population. Mountaintop-removal mining has since buried more than 1,000 miles of streams, black lung has resurged among miners cutting thin seams, and Central Appalachian output has collapsed against natural gas and Western coal."}
 ],
 sources:["West Virginia Archives and History","National Park Service","U.S. Energy Information Administration"]},
{id:"homestead",name:"Carnegie steel — Homestead",lon:-79.89,lat:40.41,from:1875,kind:"factory",tier:1,
 facts:[["1892","Battle of Homestead — locked-out workers defeated Pinkerton agents; the state militia broke the strike"],["1901","Carnegie's mills anchored U.S. Steel, the first billion-dollar corporation"]],
 eras:[
  {from:1875,to:1892,text:"Andrew Carnegie opened the Edgar Thomson Bessemer works in 1875 at Braddock, where rail met river and Connellsville coke, and acquired the neighboring Homestead works in 1883. Relentless cost-cutting and hard driving made the Monongahela valley the world's steel center, rolling rails, structural beams, and naval armor plate."},
  {from:1892,to:1936,text:"In July 1892 Henry Clay Frick locked out the Amalgamated union at Homestead; workers defeated a barge-borne Pinkerton assault in a day-long battle that killed about ten men, but the state militia broke the strike. Steel stayed non-union through four decades of twelve-hour days. U.S. Steel, formed around Carnegie's mills in 1901, was the first billion-dollar corporation."},
  {from:1936,to:2026,text:"The CIO's steelworkers organized the valley in the late 1930s; wartime Homestead employed some 15,000, expanded by razing a largely Black and immigrant ward below the tracks. Collapse came fast after 1979: Homestead closed in 1986 and was leveled for a shopping complex. The Carrie Blast Furnaces across the river survive as a National Historic Landmark."}
 ],
 sources:["Rivers of Steel National Heritage Area","Pennsylvania Historical and Museum Commission","Library of Congress"]},
{id:"blackhills",name:"Homestake Mine",lon:-103.75,lat:44.35,from:1876,to:2002,kind:"mine",tier:3,
 facts:[["Yield","About 40 million ounces of gold, 1876-2002"],["Treaty","Mined on Black Hills land guaranteed to the Lakota by the 1868 Fort Laramie Treaty"]],
 eras:[
  {from:1876,to:1900,text:"Custer's 1874 expedition confirmed gold in the Black Hills — land guaranteed to the Lakota by the 1868 Fort Laramie Treaty. Prospectors poured in illegally and the government seized the Hills in 1877. At Lead, the Manuel brothers' Homestake claim, bought by George Hearst's syndicate, grew into a deep industrial mine with its own railroads, mills, and power plants."},
  {from:1900,to:2002,text:"Homestake ran 126 years and reached 8,000 feet — the deepest mine in North America — producing about 40 million ounces of gold. Cornish, Slavic, and Italian miners worked a paternalistic company town that stayed largely non-union for decades. In a cavern nearly a mile down, Ray Davis's solar-neutrino experiment (1965-94) earned a Nobel Prize."},
  {from:2002,to:2026,text:"Low gold prices closed the mine in 2002. In 1980 the Supreme Court ruled the Black Hills had been taken unlawfully; the Lakota have refused the award — now grown past a billion dollars — and continue to seek return of the land. The workings reopened as the Sanford Underground Research Facility for dark-matter and neutrino physics."}
 ],
 sources:["South Dakota State Historical Society","Sanford Underground Research Facility","National Park Service"]},
{id:"butte",name:"Butte copper",lon:-112.53,lat:46.00,from:1882,kind:"mine",tier:2,
 facts:[["Disaster","Speculator Mine fire (1917) killed 168 — the worst U.S. hardrock mining disaster"],["Legacy","The Berkeley Pit's acid lake anchors one of the nation's largest Superfund complexes"]],
 eras:[
  {from:1882,to:1917,text:"Electrification made copper king: Marcus Daly's Anaconda mine, developed from 1882, turned Butte hill into the Richest Hill on Earth, at times supplying a major share of the world's copper. Irish immigrants made Butte one of America's most Irish cities; smelter smoke killed vegetation for miles, and the Anaconda Company came to dominate Montana's politics and newspapers."},
  {from:1917,to:1955,text:"The June 1917 Speculator Mine fire killed 168 miners, the worst hardrock mining disaster in U.S. history; weeks later vigilantes lynched IWW organizer Frank Little, and federal troops occupied the city. Company guards fired on union pickets in 1920. Through it all the mile-deep shafts fed war demand while Anaconda grew into a global copper empire."},
  {from:1955,to:2026,text:"Anaconda opened the Berkeley Pit in 1955, swallowing whole neighborhoods; ARCO halted pit mining in 1982. The pit has since filled with acidic, metal-laden water and, with the Clark Fork valley, forms one of the nation's largest Superfund complexes. A smaller modern operation still mines the hill's east side, and Butte's headframes stand as monuments."}
 ],
 sources:["Montana Historical Society","U.S. Environmental Protection Agency","Butte-Silver Bow Public Archives"]},
{id:"whiting",name:"Standard Oil Whiting refinery",lon:-87.49,lat:41.68,from:1889,kind:"refinery",tier:2,
 facts:[["Cracking","The Burton process (1913), first commercial thermal cracking, roughly doubled gasoline yields"],["Scale","Largest refinery in the Midwest, roughly 440,000 barrels per day"]],
 eras:[
  {from:1889,to:1911,text:"Standard Oil built its great refinery on Lake Michigan dunes in 1889 — far enough from Chicago to avoid complaint, close to rail and water shipping. Its purpose was refining sulfurous Lima, Ohio crude with Herman Frasch's desulfurization process. Whiting became the country's largest refinery, and a company town of Central European immigrant workers grew beside it."},
  {from:1911,to:1990,text:"After the 1911 Standard Oil breakup, Whiting anchored Standard of Indiana, later Amoco. William Burton's thermal cracking process, developed here and patented in 1913, roughly doubled gasoline yields and helped fuel the automobile age. A 1955 fluid hydroformer explosion shattered the surrounding neighborhood, yet the refinery kept expanding along the industrial Calumet lakeshore."},
  {from:1990,to:2026,text:"BP absorbed Amoco in 1998, and a multibillion-dollar modernization finished in 2013 refitted Whiting to run heavy Canadian oil-sands crude. At roughly 440,000 barrels a day it remains the largest refinery in the Midwest, long scrutinized for benzene emissions, mercury discharges to Lake Michigan, and its outsized carbon footprint."}
 ],
 sources:["BP","Indiana Historical Society","U.S. Energy Information Administration"]},
{id:"mesabi",name:"Mesabi Iron Range",lon:-92.60,lat:47.50,from:1892,kind:"mine",tier:2,
 facts:[["Output","Has supplied the majority of U.S. iron ore for over a century"],["WWII","Record wartime tonnage fed the furnaces of American victory"]],
 eras:[
  {from:1892,to:1920,text:"The Merritt brothers proved ore so soft steam shovels could dig it; the first trainload left Mountain Iron in 1892. Rockefeller and then U.S. Steel's Oliver division consolidated the range, whose open pits — Hull-Rust-Mahoning the greatest — sent ore boats down the Great Lakes to Chicago and Pittsburgh furnaces. Finnish, Slovenian, and Italian miners mounted major strikes in 1907 and 1916."},
  {from:1920,to:1955,text:"The Mesabi supplied most American iron ore, swinging from Depression idleness to WWII's insatiable demand, when the range shipped record tonnage with women joining the pit crews. High-grade direct-shipping ore was visibly running out by the 1950s, pushing E.W. Davis's taconite research from curiosity to necessity."},
  {from:1955,to:2026,text:"Taconite saved the range: plants grind hard rock and roll magnetite into pellets. Reserve Mining's dumping of tailings into Lake Superior became a landmark 1970s environmental case, forcing disposal onto land in 1980. A handful of taconite plants still supply the great majority of U.S. iron ore, shipped through Duluth and Two Harbors."}
 ],
 sources:["Minnesota Historical Society","U.S. Geological Survey","Minnesota Discovery Center"]},
{id:"niagara",name:"Adams Power Plant — Niagara",lon:-79.06,lat:43.08,from:1895,to:1961,kind:"plant-hydro",tier:1,
 facts:[["First","Large-scale AC generation began 1895; 26-mile transmission to Buffalo in 1896"],["Effect","Cheap power created the U.S. electrochemical industry — Alcoa, Carborundum, Union Carbide"]],
 eras:[
  {from:1895,to:1920,text:"The Adams plant harnessed Niagara's head with Tesla-Westinghouse polyphase alternating current, generating from August 1895 and settling the war of the currents. Its 1896 transmission to Buffalo, 26 miles away, proved AC could move power to distant cities. Cheap electricity drew the electrochemical pioneers: Pittsburgh Reduction (later Alcoa), Carborundum, and Union Carbide."},
  {from:1920,to:1961,text:"Niagara Falls became America's electrochemical capital, its riverside lined with aluminum, abrasive, alkali, and metallurgical works — some of whose buried wastes later surfaced at Love Canal. The pioneering Adams station ran until 1961, retired after the 1956 Schoellkopf plant collapse spurred construction of the vast Robert Moses project."},
  {from:1961,to:2026,text:"Most of the Adams complex was demolished; its Stanford White transformer house survives as a National Historic Landmark of the electrical age. The Robert Moses plant, among the largest U.S. hydroelectric stations, still turns the river's flow under a 1950 treaty that protects the spectacle of the falls themselves."}
 ],
 sources:["IEEE","National Park Service","New York Power Authority"]},
{id:"nome",name:"Nome & Fairbanks gold rushes",lon:-165.40,lat:64.50,from:1899,to:1920,kind:"mine",tier:3,
 facts:[["Boom","About 20,000 people reached Nome by the summer of 1900"],["Fairbanks","Felix Pedro's 1902 strike founded the Interior's gold capital"]],
 eras:[
  {from:1899,to:1909,text:"Gold on Anvil Creek in 1898 and then in Nome's beach sands set off Alaska's wildest stampede: roughly 20,000 people camped on the treeless Bering Sea shore by summer 1900, panning the beach itself. Claim-jumping and a corrupt federal judge colored the boom, Wyatt Earp ran a saloon, and Felix Pedro's 1902 strike founded Fairbanks in the Interior."},
  {from:1909,to:1920,text:"Individual diggings gave way to companies, ditches, and dredges, and Nome shrank almost as fast as it rose. Alaska Natives — the Inupiat of the Seward Peninsula — were largely barred from staking claims because they were not U.S. citizens, though the camps depended on their labor, food, and reindeer herds. By 1920 the stampede era was over."},
  {from:1920,to:2026,text:"Bucket dredges chewed the tundra profitably into the 1960s, and their hulks still dot the coast. The 1925 dog-sled serum run to icebound Nome inspired the Iditarod race. Small placer and offshore suction-dredge mining continue, while a planned deepwater port expansion marks Nome's newest strategic chapter on a thawing Arctic coast."}
 ],
 sources:["National Park Service","Alaska Historical Society","University of Alaska Fairbanks"]},
{id:"spindletop",name:"Spindletop & Gulf oil",lon:-94.05,lat:30.02,from:1901,kind:"oilfield",tier:1,
 facts:[["Gusher","January 10, 1901 — an estimated 100,000 barrels a day for nine days"],["Companies","Gulf Oil and Texaco were born in the boom"]],
 eras:[
  {from:1901,to:1925,text:"On January 10, 1901, the Lucas Gusher blew in atop a salt dome south of Beaumont, flowing an estimated 100,000 barrels a day for nine days — more than every other U.S. well combined. Gulf Oil, Texaco, and the ancestors of Exxon's Humble rose from the boom; oil fell to pennies a barrel, and railroads and steamships began converting to fuel oil."},
  {from:1925,to:2026,text:"A second boom on the dome's flanks came in the mid-1920s; later the caprock was mined for sulfur and the field faded to stripper wells and salt-dome storage. The Lucas Gusher monument and the Spindletop-Gladys City boomtown museum at Lamar University mark the spot where cheap liquid fuel remade transportation and made Texas an oil state."}
 ],
 sources:["Texas State Historical Association","American Petroleum Institute","Lamar University"]},
{id:"bingham",name:"Bingham Canyon copper",lon:-112.15,lat:40.52,from:1906,kind:"mine",tier:2,
 facts:[["Scale","Largest human-made excavation; roughly 20 million tons of copper to date"],["Method","Jackling's 1906 open-pit mass mining model spread worldwide"]],
 eras:[
  {from:1906,to:1945,text:"Engineer Daniel Jackling gambled that two-percent copper ore could pay if dug by steam shovel at colossal scale; Utah Copper began stripping Bingham Canyon in 1906, and mass mining rewrote the industry worldwide. Greek, Serbian, Japanese, and Mexican workers struck in 1912 against the padrone labor system; smelter smoke lawsuits from valley farmers forced early emission controls."},
  {from:1945,to:2026,text:"Kennecott's pit grew into the world's largest excavation — nearly three-quarters of a mile deep and two and a half miles across — yielding roughly 20 million tons of copper, more than any mine in history. A massive 2013 landslide briefly halted mining. Rio Tinto digs on, while groundwater plumes and tailings mark a century's residue."}
 ],
 sources:["Utah Division of State History","Rio Tinto Kennecott","U.S. Geological Survey"]},
{id:"portla",name:"Ports of LA & Long Beach",lon:-118.22,lat:33.74,from:1907,kind:"port",tier:1,
 facts:[["Scale","Busiest U.S. container complex; roughly 40 percent of containerized imports"],["Origin","The free harbor fight beat the Southern Pacific; Los Angeles founded its port in 1907"]],
 eras:[
  {from:1907,to:1941,text:"Los Angeles won the free harbor fight against the Southern Pacific's Santa Monica scheme; federal breakwater work began in 1899, and the city annexed San Pedro and founded its port in 1907, with Long Beach following in 1911. Dredged from mudflats, the twin harbors grew on lumber, oil, and citrus, with Japanese, Mexican, and Slavic cannery workers on Terminal Island."},
  {from:1941,to:1980,text:"War remade the harbors: shipyards launched hundreds of vessels and employed tens of thousands, while Terminal Island's Japanese American fishing village was emptied into internment camps in 1942 and razed. Afterward the ports rode containerization and the surge of transpacific trade with Japan, then China, laying rail directly onto the wharves."},
  {from:1980,to:2026,text:"Together the San Pedro Bay ports became the Western Hemisphere's busiest container complex, handling roughly 40 percent of U.S. containerized imports. Diesel exhaust long burdened harbor neighborhoods until clean-truck and shore-power programs cut emissions; the 2021 pandemic ship queue made the docks front-page news. Automation and zero-emission mandates now drive investment."}
 ],
 sources:["Port of Los Angeles","Port of Long Beach","Los Angeles Maritime Museum"]},
{id:"gary",name:"Gary Works — U.S. Steel",lon:-87.33,lat:41.62,from:1908,kind:"factory",tier:2,
 facts:[["Scale","Largest integrated steel mill in North America"],["1919","The national steel strike put Gary under federal troops"]],
 eras:[
  {from:1908,to:1945,text:"U.S. Steel built the world's largest steel plant — and a company-planned city named for chairman Elbert Gary — on empty Lake Michigan dunes with ore docks and rail on every side; steelmaking began in 1908-09. The 1919 national steel strike put Gary under Army occupation. European immigrants, Black Great Migration workers, and Mexican laborers manned its twelve-hour turns."},
  {from:1945,to:1980,text:"Postwar Gary Works employed roughly 30,000, feeding the auto and appliance booms, and union contracts built an industrial middle class. Mill smoke drifting over the dunes helped spark the fight that created Indiana Dunes National Lakeshore in 1966, even as disinvestment and white flight began hollowing the city around the plant."},
  {from:1980,to:2026,text:"Automation and imports cut the workforce to a few thousand, though Gary Works remains the largest integrated steel mill in North America. The city's population fell by half. U.S. Steel itself passed into Nippon Steel's ownership in 2025 under a national-security agreement, promising new investment in the century-old flagship."}
 ],
 sources:["Indiana Historical Society","U.S. Steel","Calumet Regional Archives (Indiana University Northwest)"]},
{id:"pearlbase",name:"Pearl Harbor naval base",lon:-157.97,lat:21.35,from:1908,kind:"port",tier:2,
 facts:[["Dec 7, 1941","The attack killed 2,403 Americans and brought the U.S. into WWII"],["Salvage","Nearly every ship sunk in the attack was raised and returned to war"]],
 eras:[
  {from:1908,to:1941,text:"The United States annexed Hawaii in 1898 with Pearl Harbor's sheltered lagoon in mind; Congress established the naval station in 1908, and dredging plus a famously collapsed-then-rebuilt drydock opened it to capital ships by 1919. Oahu became the linchpin of American power in the Pacific, ringed by airfields, Army posts, and plantation labor."},
  {from:1941,to:1945,text:"Japan's December 7, 1941 attack killed 2,403 Americans and sank or damaged nineteen ships; the USS Arizona took 1,177 crew down. Salvage divers and shipyard workers — military and civilian — refloated all but a few vessels and repaired the fleets that won Midway and the island campaigns, running Pearl as the Pacific war's great forward base."},
  {from:1945,to:2026,text:"A Cold War homeport for carriers and submarines, the base is now Joint Base Pearl Harbor-Hickam; the Arizona Memorial draws over a million visitors a year. In 2021, fuel from the WWII-era Red Hill underground tanks contaminated drinking water and sickened military families; the Navy was ordered to defuel and permanently close the facility."}
 ],
 sources:["National Park Service (Pearl Harbor National Memorial)","Naval History and Heritage Command","U.S. Navy"]},
{id:"norfolk",name:"Naval Station Norfolk",lon:-76.33,lat:36.94,from:1917,kind:"port",tier:2,
 facts:[["Scale","The largest naval base in the world"],["Origin","Built in 1917 on the grounds of the 1907 Jamestown Exposition"]],
 eras:[
  {from:1917,to:1945,text:"Entering WWI, the Navy bought the 1907 Jamestown Exposition grounds at Sewells Point and built a base within months. Hampton Roads — deep, ice-free, midway on the Atlantic coast — already hosted major shipyards. WWII made Norfolk the Atlantic Fleet's hub for convoy escorts, carriers, and amphibious training, and regional shipyard employment swelled into the tens of thousands."},
  {from:1945,to:1991,text:"Norfolk grew into the world's largest naval station and, from 1952, the seat of NATO's Atlantic command. Carriers and submarines deployed from its piers through every Cold War crisis while Navy pay anchored the Hampton Roads economy, and the base's segregated labor system gave way to the integrated postwar Navy."},
  {from:1991,to:2026,text:"Still the world's largest naval base, Norfolk supports roughly 60,000 sailors and civilians and a dozen-plus piers of warships. The land it sits on is sinking as seas rise — among the fastest rates on the Atlantic coast — and recurrent flooding of piers and neighborhoods has made the station a national test case for military climate adaptation."}
 ],
 sources:["U.S. Navy","Naval History and Heritage Command","Library of Congress"]},
{id:"baytown",name:"Houston refining complex",lon:-94.98,lat:29.74,from:1919,kind:"refinery",tier:2,
 facts:[["Scale","ExxonMobil Baytown, roughly 560,000 barrels a day, is among the largest U.S. refineries"],["Channel","The Houston Ship Channel (1914) made inland Houston a deepwater port"]],
 eras:[
  {from:1919,to:1945,text:"Humble Oil — Standard of New Jersey's Texas arm — began building its Baytown refinery in 1919 on the new Houston Ship Channel, the dredged bayou (opened 1914) that let ocean tankers reach a port safe from Galveston's hurricanes. A company town grew alongside; WWII units made toluene for TNT and synthetic rubber, seeding a petrochemical corridor."},
  {from:1945,to:2000,text:"Cheap Gulf crude, natural-gas feedstocks, and the channel made greater Houston the nation's refining and petrochemical capital, with dozens of plants lining the fifty-mile waterway. Baytown grew into one of America's largest refineries, roughly 560,000 barrels a day, integrated with vast chemical and olefins works, while refinery unions won pattern contracts across the industry."},
  {from:2000,to:2026,text:"The channel corridor now anchors much of U.S. fuel and plastics output, while largely Latino and Black fenceline communities bear benzene releases, fires, and storm-driven spills — Hurricane Harvey's 2017 floods triggered toxic releases across the complex. ExxonMobil has expanded Baytown chemicals and plans hydrogen and plastics-recycling ventures there."}
 ],
 sources:["ExxonMobil","Texas State Historical Association","U.S. Energy Information Administration"]},
{id:"permian",name:"Permian Basin",lon:-102.10,lat:31.80,from:1923,kind:"oilfield",tier:1,
 facts:[["Today","Produces roughly half of U.S. crude oil"],["1923","Santa Rita No. 1 began the endowment of the Permanent University Fund"]],
 eras:[
  {from:1923,to:1960,text:"Santa Rita No. 1 blew in on University of Texas lands in May 1923 after 21 months of cable-tool drilling, proving the Permian Basin and eventually endowing Texas universities with billions through the Permanent University Fund. Midland and Odessa boomed as pipelines crossed the desert, and by WWII West Texas crude was a strategic asset."},
  {from:1960,to:2007,text:"Conventional giants like Wasson and Spraberry made the Permian America's workhorse oil province, with waterflooding and carbon-dioxide injection coaxing more from aging fields after Texas output peaked in 1972. Repeated busts — 1986 worst of all — hollowed Midland and Odessa, whose fortunes swung with the world price."},
  {from:2007,to:2026,text:"Horizontal drilling and hydraulic fracturing in stacked shales like the Wolfcamp reversed decline into history's biggest oil boom: the Permian now yields on the order of six million barrels a day, roughly half of U.S. crude, plus vast natural gas. Flaring, produced-water disposal, and induced earthquakes accompany the bonanza; university endowments swell with it."}
 ],
 sources:["Texas State Historical Association","U.S. Energy Information Administration","University of Texas System"]},
{id:"riverrouge",name:"Ford River Rouge",lon:-83.15,lat:42.28,from:1928,kind:"factory",tier:1,
 facts:[["Peak","More than 100,000 workers around 1930"],["1937","The Battle of the Overpass galvanized the UAW's Ford campaign"]],
 eras:[
  {from:1928,to:1945,text:"Completed in 1928 to Albert Kahn's designs, Ford's Rouge was vertical integration incarnate: ore boats unloaded at its docks into blast furnaces, foundry, glass plant, and assembly lines — raw ore to finished car in days, with employment passing 100,000. Ford servicemen beat UAW organizers at the 1937 Battle of the Overpass; a 1941 strike finally unionized Ford, whose workforce included Detroit's largest concentration of Black autoworkers."},
  {from:1945,to:2000,text:"The Rouge anchored UAW pattern bargaining and postwar Detroit's industrial might, then shrank for decades as Ford dispersed production; its steel operations were spun off in 1989. Soot, slag, and river pollution defined its footprint. A 1999 powerhouse explosion killed six workers, a grim close to the century."},
  {from:2000,to:2026,text:"Bill Ford rebuilt rather than abandoned the site: the Dearborn Truck Plant (2004), roofed with sedum as a green-manufacturing showpiece, builds F-150s, and the Rouge Electric Vehicle Center added the F-150 Lightning in 2022. Public tours again run through America's most famous factory, still working after nearly a century."}
 ],
 sources:["The Henry Ford","Walter P. Reuther Library (Wayne State University)","National Park Service"]},
{id:"easttexas",name:"East Texas Oil Field",lon:-94.86,lat:32.38,from:1930,kind:"oilfield",tier:2,
 facts:[["Scale","Largest U.S. field of its day — 30,000-plus wells, more than five billion barrels"],["Order","1931 martial law, then proration — the regulatory model OPEC later studied"]],
 eras:[
  {from:1930,to:1935,text:"Wildcatter Columbus (Dad) Joiner's Daisy Bradford No. 3 struck oil near Kilgore in October 1930, revealing the largest oil field yet found in America — a black giant spanning some 140,000 acres. Derricks crowded town lots, prices crashed toward a dime a barrel, and in August 1931 the governor sent the National Guard to shut the field under martial law."},
  {from:1935,to:2026,text:"Railroad Commission proration, backed by federal hot-oil law, restored order and became the template for managing oil supply that OPEC later studied. H.L. Hunt's purchase of Joiner's leases built a famous fortune; the field filled the WWII Big Inch pipeline to the East Coast. More than five billion barrels on, stripper wells and Kilgore's derrick skyline remain."}
 ],
 sources:["Texas State Historical Association","Railroad Commission of Texas","East Texas Oil Museum (Kilgore College)"]},
{id:"tva",name:"TVA — Norris Dam & system",lon:-84.09,lat:36.22,from:1933,kind:"plant-hydro",tier:1,
 facts:[["Reach","Power, flood control, and development across seven states; about ten million customers today"],["Kingston","The 2008 coal-ash spill was the largest U.S. industrial spill by volume"]],
 eras:[
  {from:1933,to:1945,text:"The Tennessee Valley Authority, created in May 1933, attacked flood, erosion, malaria, and darkness across seven states. Norris Dam, its first, rose 1933-36, displacing about 3,000 families and thousands of graves. New Deal jobs and cheap public power lit valley farms through rural co-ops; wartime TVA electricity ran Alcoa's aluminum plants and Oak Ridge's uranium works."},
  {from:1945,to:2000,text:"TVA grew into the nation's largest public power system, pivoting from 29 hydro dams to giant coal plants — for years the country's biggest coal buyer — and an ambitious, partly abandoned nuclear program. Cheap power industrialized the valley, while strip-mined coal and smokestack emissions drew environmental critiques its founders never imagined."},
  {from:2000,to:2026,text:"In 2008 a dike failed at the Kingston plant, spilling 1.1 billion gallons of coal ash — the largest industrial spill in U.S. history — and cleanup workers later sickened and sued. TVA now retires coal in favor of gas, nuclear (Watts Bar 2, in 2016, was the first new U.S. reactor of the century), and solar, still serving about ten million people."}
 ],
 sources:["Tennessee Valley Authority","Library of Congress","Tennessee State Library and Archives"]},
{id:"bonneville",name:"Bonneville Dam",lon:-121.94,lat:45.64,from:1938,kind:"plant-hydro",tier:3,
 facts:[["First","First federal dam on the Columbia; power flowed in 1938"],["Grid","BPA's low-cost public power built the Northwest aluminum industry"]],
 eras:[
  {from:1938,to:1945,text:"Franklin Roosevelt's New Deal built Bonneville — the first federal lock and dam on the Columbia — through the Army Corps of Engineers; its generators came online in 1938. The new Bonneville Power Administration sold the output at uniform postage-stamp rates favoring public utilities, and hired Woody Guthrie for a month of songs in 1941. Wartime aluminum smelters and Portland shipyards ran on Columbia power."},
  {from:1945,to:2026,text:"Bonneville's locks opened barge navigation toward the inland Northwest, and its fish ladders became a laboratory for the salmon crisis that deepened as dams multiplied — treaty-tribe fisheries collapsed, and Celilo Falls drowned upstream in 1957. BPA's grid now balances hydropower with wind and solar; the first powerhouse is a National Historic Landmark still at work."}
 ],
 sources:["U.S. Army Corps of Engineers","Bonneville Power Administration","Oregon Historical Society"]},
{id:"willowrun",name:"Willow Run bomber plant",lon:-83.53,lat:42.24,from:1941,to:1953,kind:"factory",tier:2,
 facts:[["Output","8,685 B-24 Liberators; about one bomber an hour at the 1944 peak"],["Rosies","Tens of thousands of women helped build the bombers"]],
 eras:[
  {from:1941,to:1945,text:"Ford broke ground in 1941 on Albert Kahn's mile-long plant to mass-produce B-24 Liberator bombers like automobiles. After a painful start mocked as Will It Run, by 1944 the line delivered roughly a bomber an hour — 8,685 in all. Some 42,000 workers at peak, including thousands of women riveters and Black migrants from the South, endured a severe housing shortage on the rural site."},
  {from:1945,to:1953,text:"Bomber production stopped abruptly in mid-1945. Kaiser-Frazer leased the giant plant and built civilian cars there until 1953, when General Motors took it over for Hydra-Matic transmission production after its Livonia plant burned. The runways beside it became Willow Run Airport, a freight field ever since."},
  {from:1953,to:2026,text:"GM's transmission operation ran until 2010; demolition spared a bomber-bay section that the Yankee Air Museum preserves in honor of the plant's Rosie the Riveter workforce, alongside its flying B-17 and B-25. Much of the cleared site now hosts the American Center for Mobility, a test ground for autonomous vehicles."}
 ],
 sources:["Yankee Air Museum","The Henry Ford","National Park Service"]},
{id:"grandcoulee",name:"Grand Coulee Dam",lon:-118.98,lat:47.96,from:1942,kind:"plant-hydro",tier:1,
 facts:[["Scale","Largest U.S. power plant, about 6,800 megawatts"],["Cost","Built with no fish passage — salmon runs above the dam ended forever"]],
 eras:[
  {from:1942,to:1945,text:"Completed in 1942 after nine years of work, Grand Coulee was the largest concrete structure ever built, a Bureau of Reclamation colossus meant to irrigate the Columbia Basin. Its power went first to war: aluminum for Boeing's bombers and, secretly, Hanford's plutonium reactors. Built without fish ladders, it closed more than a thousand river miles to salmon; tribes held a Ceremony of Tears at Kettle Falls in 1940."},
  {from:1945,to:2026,text:"Postwar canals watered about 670,000 acres of the Columbia Basin Project, and a third powerhouse finished in 1980 made Coulee the largest U.S. power station at roughly 6,800 megawatts. The Colville tribes won a settlement in 1994 for drowned lands and lost fisheries; the Spokane waited until 2020 for theirs. Woody Guthrie's Roll On, Columbia keeps its myth alive."}
 ],
 sources:["Bureau of Reclamation","Washington State Historical Society","Bonneville Power Administration"]},
{id:"hanford",name:"Hanford plutonium works",lon:-119.48,lat:46.55,from:1943,to:1987,kind:"factory",tier:1,
 facts:[["Bombs","B Reactor plutonium fueled the Trinity test and the Nagasaki bomb"],["Legacy","About 56 million gallons of tank waste — America's largest environmental cleanup"]],
 eras:[
  {from:1943,to:1945,text:"The Manhattan Project chose Hanford for Columbia River cooling water, Grand Coulee power, and isolation — expelling the farm towns of Hanford and White Bluffs and the Wanapum people. DuPont ran a segregated construction camp of some 50,000 workers. B Reactor, the world's first full-scale nuclear reactor, started up in September 1944; its plutonium fueled the Trinity test and the bomb dropped on Nagasaki."},
  {from:1945,to:1987,text:"Nine reactors and massive reprocessing canyons produced most of America's weapons plutonium through the Cold War, while releases like the deliberate 1949 Green Run sent radioactive iodine over downwind farms whose residents learned of it decades later. Richland lived and breathed the bomb. The last reactor, N, shut down in 1987."},
  {from:1987,to:2026,text:"Hanford is now the nation's largest environmental cleanup: about 56 million gallons of high-level waste sit in 177 aging underground tanks, some leaking toward the Columbia, with a long-delayed vitrification plant built to immobilize it in glass and budgets running billions a year. B Reactor welcomes visitors as part of Manhattan Project National Historical Park."}
 ],
 sources:["U.S. Department of Energy","National Park Service","Atomic Heritage Foundation"]},
{id:"kennedy",name:"Cape Canaveral & KSC",lon:-80.60,lat:28.52,from:1950,kind:"spaceport",tier:1,
 facts:[["First","First launch — Bumper 8, July 24, 1950"],["Apollo 11","Left Pad 39A for the Moon on July 16, 1969"]],
 eras:[
  {from:1950,to:1961,text:"The Long Range Proving Ground fired its first rocket, Bumper 8, from Cape Canaveral on July 24, 1950 — a site chosen for its empty Atlantic downrange and southeastward launch advantage. Missile tests of Redstone, Atlas, and Titan merged into the space race: Explorer 1 rose in 1958 and Alan Shepard flew from the Cape in 1961."},
  {from:1961,to:1975,text:"For the Moon, NASA built its launch center on neighboring Merritt Island — named Kennedy Space Center in 1963 — with the Vehicle Assembly Building, giant crawlers, and Pad 39. Roughly 26,000 people worked there at Apollo's peak, and Apollo 11 departed Pad 39A on July 16, 1969. A national wildlife refuge shares the spaceport's buffer lands."},
  {from:1975,to:2026,text:"The shuttle flew 135 missions from 1981 to 2011, with Challenger and Columbia lost along the way. Commercial leases then revived the pads: SpaceX launches from 39A at a cadence no spaceport has matched, Artemis I flew in 2022, and the Space Coast now hosts more orbital launches per year than anywhere on Earth."}
 ],
 sources:["NASA","Smithsonian National Air and Space Museum","U.S. Space Force"]},
{id:"interstate",name:"Interstate Highway System",lon:-95.68,lat:39.05,from:1956,kind:"highway",tier:1,
 facts:[["1956","41,000 miles authorized; 90 percent federal funding from the gas-tax trust fund"],["Cost","Urban freeway construction displaced hundreds of thousands, disproportionately Black families"]],
 eras:[
  {from:1956,to:1975,text:"The Federal-Aid Highway Act of 1956 authorized a 41,000-mile expressway network, 90 percent federally funded through a gas-tax trust fund — Eisenhower's cold-war case sealed decades of lobbying. It became history's largest public works project. Urban routes were driven through Black and poor neighborhoods — Miami's Overtown, St. Paul's Rondo, New Orleans's Claiborne Avenue — displacing hundreds of thousands and igniting freeway revolts that stopped some segments."},
  {from:1975,to:2026,text:"Now nearly 48,000 miles, the system carries roughly a quarter of U.S. vehicle-miles, restructured trucking, retail, and suburbia, and helped hollow out passenger rail. Recent federal programs fund removing or capping a few of the most divisive urban segments, while states shoulder the endless rebuilding of 1960s concrete and bridges."}
 ],
 sources:["Federal Highway Administration","U.S. Department of Transportation","Eisenhower Presidential Library"]},
{id:"shippingport",name:"Shippingport nuclear",lon:-80.43,lat:40.62,from:1957,to:1982,kind:"plant-nuclear",tier:1,
 facts:[["First","First full-scale U.S. commercial nuclear plant — critical December 2, 1957"],["Afterlife","First U.S. reactor fully decommissioned, completed 1989"]],
 eras:[
  {from:1957,to:1982,text:"Admiral Rickover's team scaled a naval reactor into America's first full-scale commercial atomic power plant on the Ohio River below Pittsburgh; it went critical on December 2, 1957 — fifteen years to the day after Fermi's pile — and fed Duquesne Light's grid within weeks. Modest at 60 megawatts, it trained the industry and later ran a thorium light-water breeder core from 1977 to 1982."},
  {from:1982,to:2026,text:"Shut down in 1982, Shippingport became the first commercial reactor fully decommissioned in the United States: dismantled by 1989, its reactor vessel shipped whole to Hanford and the site released for reuse. The neighboring Beaver Valley reactors still run, and the project remains the proof that nuclear plants can be retired and razed."}
 ],
 sources:["U.S. Department of Energy","Nuclear Regulatory Commission","American Nuclear Society"]},
{id:"sage",name:"SAGE air-defense computers",lon:-71.27,lat:42.44,from:1958,to:1983,kind:"datacenter",tier:2,
 facts:[["Machines","IBM's AN/FSQ-7 — 250 tons and tens of thousands of vacuum tubes — were the largest computers ever built"],["Legacy","Modems, graphic displays, and real-time networking came out of SAGE"]],
 eras:[
  {from:1958,to:1963,text:"To stop Soviet bombers, MIT Lincoln Laboratory and IBM turned the Whirlwind computer into SAGE: paired AN/FSQ-7s — 250-ton, vacuum-tube machines, the largest computers ever built — filling more than twenty concrete direction centers, the first operational in 1958. Radar data flowed in over telephone-line modems to operators aiming light guns at glowing consoles: real-time networked computing was born."},
  {from:1963,to:1983,text:"SAGE cost more than the Manhattan Project and was arguably obsolete against ICBMs on arrival, yet it ran for a quarter century, the last center closing in 1983. Its contractors and thousands of trained programmers seeded the American software industry, and its architecture led directly to the SABRE airline reservation system."},
  {from:1983,to:2026,text:"The windowless blockhouses became offices, archives, or rubble; surviving console sections blink in museums and Hollywood films. SAGE's inventions — modems, video displays, light-pen pointing, networked real-time software — flowed into air traffic control and the machine rooms that grew into today's data centers, making it the ancestor of the server hall."}
 ],
 sources:["MIT Lincoln Laboratory","Computer History Museum","U.S. Air Force"]},
{id:"fourcorners",name:"Four Corners & Navajo coal plants",lon:-108.48,lat:36.69,from:1963,to:2019,kind:"plant-coal",tier:3,
 facts:[["Purpose","Navajo coal and water rights powered Phoenix, Los Angeles, and Central Arizona Project pumping"],["2019","Navajo Generating Station and the Kayenta Mine closed"]],
 eras:[
  {from:1963,to:1974,text:"Utilities sited giant mine-mouth coal plants on and beside the Navajo Nation — Four Corners from 1963, then Navajo Generating Station in the mid-1970s — to power Phoenix, Albuquerque, and Los Angeles and to pump Central Arizona Project water. Leases negotiated under federal oversight paid the tribe low royalties, and Peabody's Black Mesa mines drew down the Navajo aquifer to slurry coal."},
  {from:1974,to:2005,text:"The plants ranked among the nation's largest pollution sources, hazing the Grand Canyon until scrubber retrofits. Hundreds of Navajo and Hopi miners and operators earned wages scarce on the reservations, binding tribal budgets to coal even as households nearby lacked electricity. The Mohave plant's 2005 closure shut the Black Mesa slurry line."},
  {from:2005,to:2026,text:"Cheap gas and renewables ended the era: Navajo Generating Station and the Kayenta Mine closed in 2019, taking hundreds of jobs and a major share of Hopi and Navajo government revenue. Four Corners, partly shut since 2013, is slated to close by 2031. Solar farms, cleanup work, and disputed water settlements only partly replace what coal paid."}
 ],
 sources:["Salt River Project","U.S. Energy Information Administration","Navajo Nation"]},
{id:"glencanyon",name:"Glen Canyon Dam",lon:-111.48,lat:36.94,from:1963,kind:"plant-hydro",tier:2,
 facts:[["Reservoir","Lake Powell, the second-largest U.S. reservoir, filled in 1980"],["Flashpoint","Its construction galvanized the modern wilderness movement"]],
 eras:[
  {from:1963,to:1980,text:"The Bureau of Reclamation's 710-foot arch closed on Glen Canyon in 1963, impounding the upper Colorado as Lake Powell — keystone of the Colorado River Storage Project and cash register for Western water development. Drowning the canyon radicalized conservationists: David Brower called it his greatest defeat, and the backlash helped stop later dams proposed for the Grand Canyon."},
  {from:1980,to:2026,text:"Powell filled in 1980; the dam's 1,320 megawatts serve customers across the interior West. Downstream it re-plumbed Grand Canyon ecology — cold, clear, sediment-starved releases — prompting experimental floods since 1996. The Colorado's two-decade megadrought dropped the lake toward minimum power pool in 2022-23, reviving calls to drain it into Lake Mead."}
 ],
 sources:["Bureau of Reclamation","National Park Service (Glen Canyon NRA)","U.S. Geological Survey"]},
{id:"boeing",name:"Boeing Everett",lon:-122.27,lat:47.92,from:1967,kind:"factory",tier:2,
 facts:[["Building","World's largest building by volume — about 472 million cubic feet"],["747","1,574 jumbo jets built here; the last delivered in 2023"]],
 eras:[
  {from:1967,to:1990,text:"Betting the company on the 747, Boeing carved a plant from forest beside Paine Field in 1966-67 — by volume the largest building on Earth. The self-styled Incredibles rolled out the first jumbo in September 1968, barely sixteen months after the factory rose around them. The 1971 Boeing Bust cut tens of thousands of Puget Sound jobs before the wide-body era paid off."},
  {from:1990,to:2026,text:"Everett added the 777 in the 1990s and 787 final assembly in 2007, though Boeing later consolidated Dreamliner work in South Carolina. The last 747 rolled out in January 2023 after 1,574 were built. Machinists' strikes in 2008 and 2024 and the MAX-era crises shadow the plant, whose future rests on the delayed 777X."}
 ],
 sources:["Boeing","The Museum of Flight","HistoryLink.org"]},
{id:"prudhoe",name:"Prudhoe Bay & the pipeline",lon:-148.40,lat:70.30,from:1968,kind:"oilfield",tier:1,
 facts:[["Scale","Largest North American oil field; about 2 million barrels a day at the 1988 peak"],["Pipeline","The 800-mile Trans-Alaska Pipeline, built 1974-77, first flowed in June 1977"]],
 eras:[
  {from:1968,to:1977,text:"The 1968 ARCO-Humble discovery on Alaska's North Slope proved the largest oil field in North America — roughly 25 billion barrels in place. Development first required settling Alaska Native land claims (ANCSA, 1971: $962.5 million and 44 million acres); after the 1973 embargo Congress cleared the 800-mile Trans-Alaska Pipeline, built 1974-77 over mountains and permafrost by a workforce in the tens of thousands."},
  {from:1977,to:2026,text:"First oil reached Valdez in June 1977; Prudhoe peaked near two million barrels a day in 1988, when Alaska supplied about a quarter of U.S. crude. The 1989 Exxon Valdez wreck fouled Prince William Sound at the pipeline's far end. Output has since fallen to a fraction of peak; new Slope projects extend the line's life even as thawing permafrost unsettles its footings."}
 ],
 sources:["Alyeska Pipeline Service Company","U.S. Energy Information Administration","Alaska Department of Natural Resources"]},
{id:"powderriver",name:"Powder River Basin coal",lon:-105.50,lat:44.00,from:1972,kind:"coalfield",tier:2,
 facts:[["Share","Supplied roughly 40 percent of U.S. coal at its peak"],["Scale","North Antelope Rochelle is the largest coal mine in the world"]],
 eras:[
  {from:1972,to:2008,text:"Clean Air Act sulfur limits made Wyoming's thick, shallow, low-sulfur seams suddenly precious; Belle Ayr, opened in 1972, began the modern Powder River Basin. Draglines and 400-ton trucks strip seams tens of feet thick, and mile-long unit trains haul to power plants across dozens of states. By the 2000s the basin supplied about 40 percent of U.S. coal, with North Antelope Rochelle and Black Thunder the largest mines on Earth."},
  {from:2008,to:2026,text:"Fracked gas and renewables broke coal's grip: basin output has fallen by roughly half since the 2008 peak. Producer bankruptcies raised alarms over self-bonded reclamation obligations, and mines now consolidate or close while Gillette tries to diversify. Vast stripped acreage awaits final regrading, bond release, and a verdict on coal's Western endgame."}
 ],
 sources:["U.S. Energy Information Administration","Wyoming State Geological Survey","Bureau of Land Management"]},
{id:"tmi",name:"Three Mile Island",lon:-76.72,lat:40.15,from:1974,to:2019,kind:"plant-nuclear",tier:2,
 facts:[["1979","Partial meltdown of Unit 2 — the worst U.S. commercial nuclear accident"],["Restart","A 2024 Microsoft deal aims to restart Unit 1 for data-center power"]],
 eras:[
  {from:1974,to:1979,text:"Unit 1 entered service on a Susquehanna River island in 1974; Unit 2 followed in December 1978. On March 28, 1979, a stuck valve and misread instruments melted about half of Unit 2's core — America's worst commercial nuclear accident. Off-site radiation releases were small, but chaotic communications drove tens of thousands to flee, and the Kemeny Commission indicted industry and regulator alike."},
  {from:1979,to:2019,text:"The accident helped end new U.S. reactor orders for a generation, spawned the industry's INPO safety regime, and required a fourteen-year, roughly billion-dollar defueling of the wrecked unit. Unit 1, restarted in 1985 over local opposition, ran reliably until cheap shale gas closed it in September 2019."},
  {from:2019,to:2026,text:"Decommissioning turned to reversal: in 2024 Constellation agreed with Microsoft to restart Unit 1 — renamed the Crane Clean Energy Center — around 2027-28 to power data centers, a bellwether of AI-era electricity demand and nuclear's changed fortunes. The damaged Unit 2 is being dismantled separately."}
 ],
 sources:["Nuclear Regulatory Commission","U.S. Department of Energy","Pennsylvania Historical and Museum Commission"]},
{id:"altamont",name:"Altamont Pass wind",lon:-121.66,lat:37.73,from:1981,kind:"plant-wind",tier:2,
 facts:[["Pioneer","One of the world's first large wind farms — about 7,000 turbines by the mid-1980s"],["Wildlife","Raptor deaths forced repowering with fewer, larger turbines"]],
 eras:[
  {from:1981,to:2000,text:"PURPA contracts and generous state and federal tax credits sent wind prospectors to the gusty pass between the Bay Area and the Central Valley; by the mid-1980s some 7,000 small turbines spun at Altamont, then the largest concentration of wind machines on Earth. The young industry proved itself here — and embarrassed itself when credits lapsed and firms folded."},
  {from:2000,to:2026,text:"Altamont's lattice towers stood in golden-eagle country and killed thousands of raptors; lawsuits and settlements from 2005 forced seasonal shutdowns and then wholesale repowering. A few hundred large modern turbines now out-generate the old fleet with far fewer deaths, and the pass remains both a working wind farm and the industry's founding cautionary tale."}
 ],
 sources:["U.S. Department of Energy","California Energy Commission","Alameda County"]},
{id:"palverde",name:"Palo Verde nuclear",lon:-112.87,lat:33.39,from:1986,kind:"plant-nuclear",tier:2,
 facts:[["Output","America's largest power producer for roughly three decades — about 32 TWh a year"],["Water","The only large U.S. nuclear plant cooled entirely with reclaimed wastewater"]],
 eras:[
  {from:1986,to:2000,text:"A consortium of Southwestern utilities built three large pressurized-water reactors in the desert west of Phoenix, entering service between 1986 and 1988 — the only major U.S. nuclear plant sited on no river, lake, or coast. It condenses its steam with billions of gallons a year of treated Phoenix-area municipal wastewater, a siting gamble that has defined it since."},
  {from:2000,to:2026,text:"With about 3,900 megawatts across three units, Palo Verde has been the nation's largest generator of electricity for roughly three decades, sending around 32 terawatt-hours a year to some four million customers across Arizona, California, New Mexico, and Texas. Licenses extend into the 2040s, and its wastewater cooling is studied for reactors in a drying West."}
 ],
 sources:["Arizona Public Service","Nuclear Regulatory Commission","U.S. Energy Information Administration"]},
{id:"ashburn",name:"\"Data Center Alley\" — Northern Virginia",lon:-77.49,lat:39.04,from:1992,kind:"datacenter",tier:1,
 facts:[["Lineage","MAE-East, UUNET, and AOL rooted the internet in Northern Virginia"],["Today","The world's largest data-center cluster carries a major share of global internet traffic"]],
 eras:[
  {from:1992,to:2007,text:"Northern Virginia's defense-and-telecom belt birthed the commercial internet: MAE-East (1992) was the exchange where early backbones peered, UUNET ran one of the first commercial backbones, and AOL's dial-up empire grew in Dulles. Equinix opened its Ashburn campus in 1999 as carriers laced Loudoun County farmland with some of the densest fiber on Earth."},
  {from:2007,to:2026,text:"Cloud computing turned Data Center Alley into the world's largest concentration of data centers — hundreds of buildings carrying a major share of global internet traffic, drawn by fiber, land, tax incentives, and Dominion power. The AI boom has pushed county data-center demand past several gigawatts, straining the grid and fueling fights over sprawl, noise, water, and transmission lines."}
 ],
 sources:["Loudoun County Department of Economic Development","Virginia Economic Development Partnership","U.S. Energy Information Administration"]},
{id:"bakken",name:"Bakken shale",lon:-103.20,lat:47.80,from:2008,kind:"oilfield",tier:2,
 facts:[["Boom","Made North Dakota the No. 2 oil-producing state by 2012"],["Peak","About 1.5 million barrels a day in 2019"]],
 eras:[
  {from:2008,to:2015,text:"Horizontal drilling and multistage fracking, proved at Elm Coulee and Parshall, unlocked the tight Bakken and Three Forks; from 2008 North Dakota vaulted to the nation's second-largest oil producer. Williston's man camps, hundred-car oil trains — whose dangers the 2013 Lac-Megantic disaster made plain — widespread flaring, and drilling on the Fort Berthold Reservation defined the rush."},
  {from:2015,to:2026,text:"Output peaked near 1.5 million barrels a day in 2019. The Dakota Access Pipeline, finished after the 2016-17 Standing Rock protests over water and treaty rights, now carries much of the crude. Production has plateaued around a million barrels daily, flaring has fallen, and the MHA Nation both profits from and litigates over the oil beneath its land."}
 ],
 sources:["North Dakota Department of Mineral Resources","U.S. Energy Information Administration","U.S. Geological Survey"]},
{id:"marcellus",name:"Marcellus shale gas",lon:-76.90,lat:41.00,from:2008,kind:"gasfield",tier:2,
 facts:[["Scale","Largest U.S. gas field; Appalachia yields over a third of U.S. natural gas"],["Effect","Underpinned America's rise to the world's top gas producer and LNG exporter"]],
 eras:[
  {from:2008,to:2015,text:"Range Resources' Washington County wells in the mid-2000s adapted Barnett-style fracking to the mile-deep Marcellus, and a leasing frenzy swept Pennsylvania and West Virginia from 2008. Landmen, royalties, and rig traffic transformed farm counties; contaminated water wells at Dimock became a national flashpoint, and New York banned fracking outright in 2014."},
  {from:2015,to:2026,text:"The Marcellus and underlying Utica made Appalachia America's gas engine — more than a third of U.S. dry gas — flipping the country into the world's top producer and largest LNG exporter. Pipeline fights raged for a decade; cheap gas killed coal plants and cut power-sector emissions while leaking methane along the way."}
 ],
 sources:["U.S. Energy Information Administration","U.S. Geological Survey","Pennsylvania Department of Environmental Protection"]},
{id:"thedalles",name:"Google The Dalles data center",lon:-121.18,lat:45.60,from:2006,kind:"datacenter",tier:2,
 facts:[["First","Google's first purpose-built data center opened here in 2006"],["Site logic","Columbia River hydropower, fiber, tax breaks, and cool dry air"]],
 eras:[
  {from:2006,to:2015,text:"Google built its first company-designed data center on the Columbia at The Dalles, opening in 2006 beside cheap federal hydropower, a long-haul fiber route, local tax abatements, and a dry climate good for cooling — in a town whose aluminum smelter had once claimed the same electricity. The secretive Project 02 set the tone for an industry that followed it up the river."},
  {from:2015,to:2026,text:"The campus grew to multiple buildings and Google spread across Oregon. A newspaper's 2022 public-records lawsuit revealed the site used more than a quarter of the city's water for cooling, sharpening scrutiny of hyperscale siting in dry country; Google has since funded aquifer and water projects while pledging to replenish more water than it consumes."}
 ],
 sources:["Google","Northern Wasco County PUD","Oregon Historical Society"]},
{id:"ivanpah",name:"Mojave desert solar",lon:-115.47,lat:35.56,from:2014,kind:"plant-solar",tier:2,
 facts:[["Scale","Ivanpah (392 MW) was the world's largest concentrating solar plant at its 2014 debut"],["Turn","Cheap photovoltaic panels made its power towers obsolete within a decade"]],
 eras:[
  {from:2014,to:2020,text:"Ivanpah's three 459-foot power towers, ringed by more than 170,000 mirror assemblies, lit up in February 2014 — the world's largest concentrating solar plant, backed by a $1.6 billion federal loan guarantee and investors including NRG and Google. Biologists relocated desert tortoises from its footprint, focused solar flux singed passing birds, and natural-gas burners helped the boilers along."},
  {from:2020,to:2026,text:"Plummeting photovoltaic costs made the towers uncompetitive: PG&E moved to end its Ivanpah contracts, and most of the plant is slated to shut by 2026, while vast photovoltaic-plus-battery farms now carpet the Mojave and power California's evenings. Ivanpah stands as a bold, briefly state-of-the-art dead end — and a lesson in how fast energy technology can turn."}
 ],
 sources:["U.S. Department of Energy","California Energy Commission","U.S. Fish and Wildlife Service"]},
{id:"blockisland",name:"Block Island offshore wind",lon:-71.52,lat:41.11,from:2016,kind:"plant-wind",tier:3,
 facts:[["First","First U.S. offshore wind farm — five turbines, 30 MW, December 2016"],["Effect","Retired Block Island's diesel generators and proved the East Coast model"]],
 eras:[
  {from:2016,to:2020,text:"Deepwater Wind's five 6-megawatt turbines off Block Island began spinning in December 2016 — the first offshore wind farm in the Americas. Modest at 30 megawatts, the project let the island retire its diesel generators and connect to the mainland grid by new submarine cable, with jack-up vessels and crews borrowed from Gulf of Mexico oil experience."},
  {from:2020,to:2026,text:"Under Orsted's ownership, Block Island became the proof-of-concept for an East Coast industry: federal lease auctions, port build-outs, and utility-scale projects like South Fork and Vineyard Wind followed, along with fights over fisheries, whales, and costs that sank several projects in the 2023-24 squeeze. The five pioneer turbines keep turning."}
 ],
 sources:["U.S. Department of Energy","Bureau of Ocean Energy Management","Orsted"]},
{id:"sabinelng",name:"Sabine Pass LNG",lon:-93.87,lat:29.73,from:2016,kind:"port",tier:2,
 facts:[["First","First LNG export cargo from the Lower 48 sailed in February 2016"],["Effect","Anchored America's rise to the world's largest LNG exporter by 2023"]],
 eras:[
  {from:2016,to:2020,text:"Cheniere's Sabine Pass terminal was built in the 2000s to import gas; the shale glut flipped its purpose, and in February 2016 it shipped the first liquefied-natural-gas export cargo from the Lower 48. Liquefaction trains multiplied on the marshy Louisiana-Texas line, making the Sabine-Neches channel the beachhead of an entirely new export industry."},
  {from:2020,to:2026,text:"Six trains now liquefy about 30 million tonnes a year, and Sabine Pass anchored America's rise to the world's largest LNG exporter by 2023, rerouting gas to Europe after Russia's 2022 invasion of Ukraine. A widening string of Gulf terminals follows it, debated over methane leakage, air permits in fenceline communities, and domestic price exposure."}
 ],
 sources:["Cheniere Energy","U.S. Energy Information Administration","Federal Energy Regulatory Commission"]},
{id:"tsmcaz",name:"TSMC Arizona fabs",lon:-112.10,lat:33.72,from:2020,kind:"factory",tier:2,
 facts:[["CHIPS","A $6.6 billion CHIPS Act award backs the Phoenix campus"],["Milestone","Volume production of 4-nanometer chips began in late 2024"]],
 eras:[
  {from:2020,to:2024,text:"TSMC announced its Phoenix campus in May 2020 amid the U.S.-China technology rupture, and the CHIPS and Science Act of 2022 later backed it with $6.6 billion in grants. Construction drew thousands of building-trades workers — and friction over imported Taiwanese specialists — while Arizona bet that water recycling could host leading-edge fabs beside its old Motorola and Intel chip heritage."},
  {from:2024,to:2026,text:"The first fab began high-volume production of 4-nanometer chips in late 2024 — the most advanced semiconductors yet made on American soil, with yields reported to rival Taiwan's. TSMC has raised its Arizona commitment to $165 billion for additional fabs, advanced packaging, and R&D, aiming to build a U.S. cluster for AI-era silicon in the CHIPS Act's signature reshoring test."}
 ],
 sources:["TSMC","U.S. Department of Commerce","Arizona Commerce Authority"]}
];
